class DSU {
    parent: number[];
    rank: number[];
    // parity[i] stores the parity of the path weight from node i to parent[i]
    parity: number[]; 

    constructor(n: number) {
        this.parent = Array(n).fill(0).map((_, i) => i);
        this.rank = Array(n).fill(0);
        this.parity = Array(n).fill(0);
    }

    // Returns [root, parity_to_root]
    find(i: number): [number, number] {
        if (this.parent[i] === i) {
            return [i, 0];
        }

        // Recurse to find the ultimate root and its parity distance
        const [root, rootParity] = this.find(this.parent[i]);

        // Update parity[i]: old path i -> parent[i] combined with parent[i] -> root
        this.parity[i] = this.parity[i] ^ rootParity;

        // Path compression
        this.parent[i] = root;

        return [root, this.parity[i]];
    }

    // Tries to unite u and v with edge weight w.
    // Returns true if the edge is accepted (i.e., cycle condition met or no cycle formed).
    union(u: number, v: number, w: number): boolean {
        const [rootU, parityU] = this.find(u);
        const [rootV, parityV] = this.find(v);

        if (rootU === rootV) {
            // Same component: Check cycle condition.
            // Path U -> V parity = parityU XOR parityV.
            // Cycle weight parity = (parityU XOR parityV) XOR w.
            // Must be 0 for acceptance (even cycle).
            const cycleParity = parityU ^ parityV ^ w;
            return cycleParity === 0;
        } else {
            // Different components: Merge them.

            // Union by rank heuristic
            if (this.rank[rootU] < this.rank[rootV]) {
                // Swap roles to ensure rootU is the higher or equal rank component representative
                return this.union(v, u, w); 
            }

            // Merge rootV into rootU
            this.parent[rootV] = rootU;

            // Update rank if ranks were equal
            if (this.rank[rootU] === this.rank[rootV]) {
                this.rank[rootU]++;
            }

            // Calculate parity[rootV] = P(rootV -> rootU)
            // Path: rootV ---[p_v]---> v --[w]--> u ---[p_u]---> rootU
            // P(rootV -> rootU) = p_v XOR w XOR p_u.
            this.parity[rootV] = parityV ^ w ^ parityU;

            return true;
        }
    }
}

function solve(n: number, edges: number[][]): number {
    const dsu = new DSU(n);
    let addedEdgesCount = 0;

    for (const edge of edges) {
        const u = edge[0];
        const v = edge[1];
        const w = edge[2];

        // If union returns true, the edge is accepted.
        if (dsu.union(u, v, w)) {
            addedEdgesCount++;
        }
    }

    return addedEdgesCount;
}

