            // Case 1: u and v are already in the same component. Adding edge (u, v) creates a cycle.
            // Cycle parity = (Path u->v in tree) + w
            // Path u->v in tree parity = p_u XOR p_v (since p_u is u->root, p_v is v->root)
            const cycle_parity = (p_u + p_v + w) % 2;

            // The edge is accepted only if the cycle parity is 0 (even).
            if (cycle_parity === 0) {
                accepted_edges_count++;
            }
            // If cycle_parity is 1, the edge is rejected.
        } else {
            // Case 2: u and v are in different components. We merge them.

            // We merge rootV into rootU (arbitrarily choosing rootU as the new root)
            parent[rootV] = rootU;

            // We need to calculate the new relative parity d[rootV] such that:
            // Path(u -> rootU) XOR Path(rootU -> rootV) XOR Path(rootV -> v) = w (edge weight)
            // p_u XOR d[rootV] XOR p_v = w
            // d[rootV] = w XOR p_u XOR p_v

            // Since we are using addition mod 2, XOR is equivalent to addition mod 2.
            const new_relative_parity = (w + p_u + p_v) % 2;
            parity[rootV] = new_relative_parity;

            accepted_edges_count++;
        }
    }

    return accepted_edges_count;
}
